import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import apiService from '../services/apiService';
import {
    Container,
    Paper,
    Typography,
    Box,
    Button,
    CircularProgress,
    FormControl,
    InputLabel,
    Select,
    MenuItem
} from '@mui/material';
import MicIcon from '@mui/icons-material/Mic';
import StopIcon from '@mui/icons-material/Stop';
import { Editor } from '@monaco-editor/react';

const CodeTranscriptionPage = () => {
    const { user } = useAuth();
    const [isRecording, setIsRecording] = useState(false);
    const [transcribedCode, setTranscribedCode] = useState('');
    const [loading, setLoading] = useState(false);
    const [language, setLanguage] = useState('python');
    const mediaRecorderRef = useRef(null);
    const audioChunksRef = useRef([]);

    useEffect(() => {
        // Initialize any necessary audio/transcription services here
    }, []);

    const startRecording = async () => {
        try {
            const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
            const mediaRecorder = new MediaRecorder(stream);
            mediaRecorderRef.current = mediaRecorder;
            audioChunksRef.current = [];

            mediaRecorder.ondataavailable = (e) => {
                if (e.data.size > 0) {
                    audioChunksRef.current.push(e.data);
                }
            };

            mediaRecorder.onstop = async () => {
                const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
                await handleTranscribe(audioBlob);
            };

            mediaRecorder.start();
            setIsRecording(true);
        } catch (error) {
            console.error('Failed to start recording:', error);
            alert('Failed to access microphone. Please check permissions.');
        }
    };

    const stopRecording = async () => {
        if (mediaRecorderRef.current && isRecording) {
            mediaRecorderRef.current.stop();
            setIsRecording(false);
            mediaRecorderRef.current.stream.getTracks().forEach(track => track.stop());
        }
    };

    const handleTranscribe = async (audioBlob) => {
        setLoading(true);
        try {
            const result = await apiService.transcribeAudio(audioBlob);
            if (result.transcript) {
                setTranscribedCode(prev => (prev ? prev + '\n' : '') + result.transcript);
            }
        } catch (e) {
            console.error('Transcription failed', e);
            alert('Transcription failed');
        }
        setLoading(false);
    };

    return (
        <Container maxWidth="lg">
            <Box sx={{ mt: 4 }}>
                <Typography variant="h4" component="h1" gutterBottom>
                    Live Code Transcription{user?.name ? ` — Hello, ${user.name}` : ''}
                </Typography>
                <Typography color="textSecondary" paragraph>
                    Speak your code and watch it appear in real-time
                </Typography>

                <Box sx={{ display: 'flex', gap: 2, mb: 3 }}>
                    <FormControl sx={{ minWidth: 200 }}>
                        <InputLabel>Language</InputLabel>
                        <Select value={language} label="Language" onChange={(e) => setLanguage(e.target.value)}>
                            <MenuItem value="python">Python</MenuItem>
                            <MenuItem value="javascript">JavaScript</MenuItem>
                            <MenuItem value="java">Java</MenuItem>
                            <MenuItem value="cpp">C++</MenuItem>
                        </Select>
                    </FormControl>
                    <Button
                        variant="contained"
                        color={isRecording ? "secondary" : "primary"}
                        startIcon={isRecording ? <StopIcon /> : <MicIcon />}
                        onClick={isRecording ? stopRecording : startRecording}
                        disabled={loading}
                    >
                        {isRecording ? 'Stop Recording' : 'Start Recording'}
                    </Button>
                </Box>

                {loading && (
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, mb: 2 }}>
                        <CircularProgress size={20} />
                        <Typography>Transcribing...</Typography>
                    </Box>
                )}

                <Paper elevation={3} sx={{ height: '60vh' }}>
                    <Editor
                        height="100%"
                        defaultLanguage={language === 'cpp' ? 'cpp' : language}
                        value={transcribedCode}
                        options={{
                            readOnly: loading,
                            minimap: { enabled: false },
                            fontSize: 14
                        }}
                        onChange={(value) => setTranscribedCode(value)}
                    />
                </Paper>
            </Box>
        </Container>
    );
};

export default CodeTranscriptionPage;
